BEGIN;

UPDATE donations
SET charity_name = CASE charity_id::text
  WHEN '11111111-1111-1111-1111-111111111111' THEN 'Feeding America'
  WHEN '22222222-2222-2222-2222-222222222222' THEN 'St. Jude Children''s Research Hospital'
  WHEN '33333333-3333-3333-3333-333333333333' THEN 'American Red Cross'
  WHEN '44444444-4444-4444-4444-444444444444' THEN 'The Nature Conservancy'
  WHEN '55555555-5555-5555-5555-555555555555' THEN 'ASPCA'
  WHEN '66666666-6666-6666-6666-666666666666' THEN 'DonorsChoose'
  WHEN '77777777-7777-7777-7777-777777777777' THEN 'charity: water'
  WHEN '88888888-8888-8888-8888-888888888888' THEN 'Washtenaw Food Hub'
  ELSE charity_name
END
WHERE charity_id::text IN (
  '11111111-1111-1111-1111-111111111111',
  '22222222-2222-2222-2222-222222222222',
  '33333333-3333-3333-3333-333333333333',
  '44444444-4444-4444-4444-444444444444',
  '55555555-5555-5555-5555-555555555555',
  '66666666-6666-6666-6666-666666666666',
  '77777777-7777-7777-7777-777777777777',
  '88888888-8888-8888-8888-888888888888'
);

UPDATE recurring_schedules
SET charity_name = CASE charity_id::text
  WHEN '11111111-1111-1111-1111-111111111111' THEN 'Feeding America'
  WHEN '22222222-2222-2222-2222-222222222222' THEN 'St. Jude Children''s Research Hospital'
  WHEN '33333333-3333-3333-3333-333333333333' THEN 'American Red Cross'
  WHEN '44444444-4444-4444-4444-444444444444' THEN 'The Nature Conservancy'
  WHEN '55555555-5555-5555-5555-555555555555' THEN 'ASPCA'
  WHEN '66666666-6666-6666-6666-666666666666' THEN 'DonorsChoose'
  WHEN '77777777-7777-7777-7777-777777777777' THEN 'charity: water'
  WHEN '88888888-8888-8888-8888-888888888888' THEN 'Washtenaw Food Hub'
  ELSE charity_name
END
WHERE charity_id::text IN (
  '11111111-1111-1111-1111-111111111111',
  '22222222-2222-2222-2222-222222222222',
  '33333333-3333-3333-3333-333333333333',
  '44444444-4444-4444-4444-444444444444',
  '55555555-5555-5555-5555-555555555555',
  '66666666-6666-6666-6666-666666666666',
  '77777777-7777-7777-7777-777777777777',
  '88888888-8888-8888-8888-888888888888'
);

COMMIT;
